1	/**
2	 * Unit tests for the retry ladder (src/server/pipeline/retry-ladder.ts).
3	 *
4	 * All tests are pure: no I/O, no SQLite, no side effects.
5	 *
6	 * Coverage map — feat-pipeline-engine AC-3:
7	 *   "Retry ladder applies in order: attempt 1 = continue (-c),
8	 *    attempt 2 = fresh_with_failure_summary, attempt 3 = awaiting_user;
9	 *    configurable max_outer_retries per phase."
10	 */
11	
12	import { describe, it, expect } from 'vitest';
13	import {
14	  computeRetryDecision,
15	  DEFAULT_RETRY_LADDER,
16	  DEFAULT_MAX_OUTER_RETRIES,
17	  type RetryMode,
18	} from '../../src/server/pipeline/retry-ladder.js';
19	
20	// ---------------------------------------------------------------------------
21	// Default ladder
22	// ---------------------------------------------------------------------------
23	
24	describe('computeRetryDecision — default ladder', () => {
25	  it('retry_count=0 → retry with continue (attempt 1)', () => {
26	    const result = computeRetryDecision({
27	      retryCount: 0,
28	      maxOuterRetries: DEFAULT_MAX_OUTER_RETRIES,
29	      retryLadder: DEFAULT_RETRY_LADDER,
30	    });
31	    expect(result).toEqual({ kind: 'retry', mode: 'continue', nextRetryCount: 1 });
32	  });
33	
34	  it('retry_count=1 → retry with fresh_with_failure_summary (attempt 2)', () => {
35	    const result = computeRetryDecision({
36	      retryCount: 1,
37	      maxOuterRetries: DEFAULT_MAX_OUTER_RETRIES,
38	      retryLadder: DEFAULT_RETRY_LADDER,
39	    });
40	    expect(result).toEqual({
41	      kind: 'retry',
42	      mode: 'fresh_with_failure_summary',
43	      nextRetryCount: 2,
44	    });
45	  });
46	
47	  it('retry_count=2 → exhausted (ladder entry is awaiting_user sentinel)', () => {
48	    const result = computeRetryDecision({
49	      retryCount: 2,
50	      maxOuterRetries: DEFAULT_MAX_OUTER_RETRIES,
51	      retryLadder: DEFAULT_RETRY_LADDER,
52	    });
53	    expect(result).toEqual({ kind: 'exhausted' });
54	  });
55	
56	  it('retry_count=3 → exhausted (at cap)', () => {
57	    const result = computeRetryDecision({
58	      retryCount: 3,
59	      maxOuterRetries: DEFAULT_MAX_OUTER_RETRIES,
60	      retryLadder: DEFAULT_RETRY_LADDER,
61	    });
62	    expect(result).toEqual({ kind: 'exhausted' });
63	  });
64	
65	  it('retry_count > maxOuterRetries → exhausted (over limit)', () => {
66	    const result = computeRetryDecision({
67	      retryCount: 10,
68	      maxOuterRetries: DEFAULT_MAX_OUTER_RETRIES,
69	      retryLadder: DEFAULT_RETRY_LADDER,
70	    });
71	    expect(result).toEqual({ kind: 'exhausted' });
72	  });
73	});
74	
75	// ---------------------------------------------------------------------------
76	// maxOuterRetries = 0 (never retry)
77	// ---------------------------------------------------------------------------
78	
79	describe('computeRetryDecision — max_outer_retries = 0', () => {
80	  it('always exhausted immediately', () => {
81	    const result = computeRetryDecision({
82	      retryCount: 0,
83	      maxOuterRetries: 0,
84	      retryLadder: DEFAULT_RETRY_LADDER,
85	    });
86	    expect(result).toEqual({ kind: 'exhausted' });
87	  });
88	});
89	
90	// ---------------------------------------------------------------------------
91	// maxOuterRetries = 1 (one retry only)
92	// ---------------------------------------------------------------------------
93	
94	describe('computeRetryDecision — max_outer_retries = 1', () => {
95	  it('retry_count=0 → retry with continue', () => {
96	    const result = computeRetryDecision({
97	      retryCount: 0,
98	      maxOuterRetries: 1,
99	      retryLadder: DEFAULT_RETRY_LADDER,
100	    });
101	    expect(result).toEqual({ kind: 'retry', mode: 'continue', nextRetryCount: 1 });
102	  });
103	
104	  it('retry_count=1 → exhausted (cap reached)', () => {
105	    const result = computeRetryDecision({
106	      retryCount: 1,
107	      maxOuterRetries: 1,
108	      retryLadder: DEFAULT_RETRY_LADDER,
109	    });
110	    expect(result).toEqual({ kind: 'exhausted' });
111	  });
112	});
113	
114	// ---------------------------------------------------------------------------
115	// Custom retry ladders
116	// ---------------------------------------------------------------------------
117	
118	describe('computeRetryDecision — custom retry_ladder', () => {
119	  it('ladder with fresh_with_diff at slot 0', () => {
120	    const customLadder: readonly RetryMode[] = ['fresh_with_diff', 'fresh_with_failure_summary'];
121	    const result = computeRetryDecision({
122	      retryCount: 0,
123	      maxOuterRetries: 2,
124	      retryLadder: customLadder,
125	    });
126	    expect(result).toEqual({ kind: 'retry', mode: 'fresh_with_diff', nextRetryCount: 1 });
127	  });
128	
129	  it('ladder with awaiting_user sentinel at slot 0 → immediately exhausted', () => {
130	    const customLadder: readonly RetryMode[] = ['awaiting_user', 'continue'];
131	    const result = computeRetryDecision({
132	      retryCount: 0,
133	      maxOuterRetries: 2,
134	      retryLadder: customLadder,
135	    });
136	    expect(result).toEqual({ kind: 'exhausted' });
137	  });
138	
139	  it('awaiting_user sentinel mid-ladder → exhausted before cap', () => {
140	    const customLadder: readonly RetryMode[] = ['continue', 'awaiting_user', 'fresh_with_diff'];
141	    // retry_count=1 hits the sentinel before reaching cap=3
142	    const result = computeRetryDecision({
143	      retryCount: 1,
144	      maxOuterRetries: 3,
145	      retryLadder: customLadder,
146	    });
147	    expect(result).toEqual({ kind: 'exhausted' });
148	  });
149	
150	  it('ladder shorter than maxOuterRetries → uses awaiting_user for out-of-bounds slots', () => {
151	    // ladder has 1 entry; retryCount=1 is past the end → treated as awaiting_user
152	    const customLadder: readonly RetryMode[] = ['continue'];
153	    const result = computeRetryDecision({
154	      retryCount: 1,
155	      maxOuterRetries: 5, // cap not reached
156	      retryLadder: customLadder,
157	    });
158	    // ladder[1] is undefined → sentinel → exhausted
159	    expect(result).toEqual({ kind: 'exhausted' });
160	  });
161	
162	  it('fresh_with_diff at every slot', () => {
163	    const allDiff: readonly RetryMode[] = [
164	      'fresh_with_diff',
165	      'fresh_with_diff',
166	      'fresh_with_diff',
167	    ];
168	    for (let i = 0; i < 3; i++) {
169	      const result = computeRetryDecision({
170	        retryCount: i,
171	        maxOuterRetries: 3,
172	        retryLadder: allDiff,
173	      });
174	      expect(result).toEqual({ kind: 'retry', mode: 'fresh_with_diff', nextRetryCount: i + 1 });
175	    }
176	    // At cap
177	    const atCap = computeRetryDecision({
178	      retryCount: 3,
179	      maxOuterRetries: 3,
180	      retryLadder: allDiff,
181	    });
182	    expect(atCap).toEqual({ kind: 'exhausted' });
183	  });
184	});
185	
186	// ---------------------------------------------------------------------------
187	// nextRetryCount is always retryCount + 1
188	// ---------------------------------------------------------------------------
189	
190	describe('computeRetryDecision — nextRetryCount invariant', () => {
191	  it('nextRetryCount = retryCount + 1 for all retry slots', () => {
192	    const ladder: readonly RetryMode[] = ['continue', 'fresh_with_failure_summary'];
193	    for (let retryCount = 0; retryCount < 2; retryCount++) {
194	      const result = computeRetryDecision({ retryCount, maxOuterRetries: 2, retryLadder: ladder });
195	      if (result.kind === 'retry') {
196	        expect(result.nextRetryCount).toBe(retryCount + 1);
197	      }
198	    }
199	  });
200	});
201	
202	// ---------------------------------------------------------------------------
203	// DEFAULT_RETRY_LADDER and DEFAULT_MAX_OUTER_RETRIES constants
204	// ---------------------------------------------------------------------------
205	
206	describe('DEFAULT constants', () => {
207	  it('DEFAULT_RETRY_LADDER has 3 entries', () => {
208	    expect(DEFAULT_RETRY_LADDER).toHaveLength(3);
209	  });
210	
211	  it('DEFAULT_RETRY_LADDER follows the spec order', () => {
212	    expect(DEFAULT_RETRY_LADDER[0]).toBe('continue');
213	    expect(DEFAULT_RETRY_LADDER[1]).toBe('fresh_with_failure_summary');
214	    expect(DEFAULT_RETRY_LADDER[2]).toBe('awaiting_user');
215	  });
216	
217	  it('DEFAULT_MAX_OUTER_RETRIES is 3', () => {
218	    expect(DEFAULT_MAX_OUTER_RETRIES).toBe(3);
219	  });
220	
221	  it('DEFAULT_RETRY_LADDER length equals DEFAULT_MAX_OUTER_RETRIES', () => {
222	    expect(DEFAULT_RETRY_LADDER.length).toBe(DEFAULT_MAX_OUTER_RETRIES);
223	  });
224	});
