0	/**
1	 * Pipeline Engine — core atomic state-machine operations over SQLite.
2	 *
3	 * Source: plan-draft3.md §State Machine, §Retry, §Crash Recovery;
4	 * docs/design/state-machine-transitions.md; feat-pipeline-engine spec.
5	 *
6	 * ## Guarantees
7	 *
8	 *   AC-5  Pipeline Engine is the ONLY component that mutates SQLite
9	 *         workflow/item/session state.  No other module calls db.writer
10	 *         directly.
11	 *   AC-6  Every transition is committed inside db.transaction() before any
12	 *         observable external side effect (process spawn, WS frame emission).
13	 *   RC-1  No long-lived in-memory workflow state.  Every public function
14	 *         re-reads SQLite at the start of each call; none caches item/
15	 *         workflow rows between calls.
16	 *
17	 * ## Exported functions
18	 *
19	 *   applyItemTransition   — atomically apply a state-machine event to an item
20	 *   checkStageComplete    — probe whether all items in a stage are terminal
21	 *   buildCrashRecovery    — rebuild projection from SQLite on startup
22	 *
23	 * ## Non-responsibilities
24	 *
25	 *   - Does NOT spawn processes (ProcessManager's job).
26	 *   - Does NOT create worktrees (WorktreeManager's job).
27	 *   - Does NOT assemble prompts (Prompt Assembler's job).
28	 *   - Does NOT parse NDJSON (StreamJsonParser's job).
29	 *   - Does NOT run the scheduling event loop (higher-level concern).
30	 */
31	
32	import type { DbPool } from '../storage/db.js';
33	import type { State, Event } from '../state-machine/states.js';
34	import { transition } from '../state-machine/transitions.js';
35	import type { TransitionResult } from '../state-machine/transitions.js';
36	import type { FailureClass } from '../state-machine/classifier.js';
37	import {
38	  computeRetryDecision,
39	  DEFAULT_RETRY_LADDER,
40	  DEFAULT_MAX_OUTER_RETRIES,
41	} from './retry-ladder.js';
42	import type { RetryMode } from './retry-ladder.js';
43	
44	// ---------------------------------------------------------------------------
45	// Public types — action grammar (subset consumed by the engine)
46	// ---------------------------------------------------------------------------
47	
48	/** Resolved action from a pre/post command's exit-code map. */
49	export interface ResolvedAction {
50	  kind: 'continue' | 'goto' | 'retry' | 'stop-and-ask' | 'stop' | 'fail';
51	  /** Target phase name for 'goto' actions. */
52	  goto?: string;
53	  /** Max goto loops to this destination (default 3). */
54	  maxRevisits?: number;
55	  /** Retry configuration for 'retry' actions (not used by outer ladder). */
56	  retry?: { mode: Exclude<RetryMode, 'awaiting_user'>; max: number };
57	  /** Failure reason for 'fail' actions. */
58	  failReason?: string;
59	}
60	
61	// ---------------------------------------------------------------------------
62	// Public types — guard context
63	// ---------------------------------------------------------------------------
64	
65	/**
66	 * Caller-supplied context for guard evaluation.
67	 *
68	 * The engine reads state-dependent guards (retry_count, depends_on,
69	 * worktree_path) directly from SQLite.  Guards that come from external
70	 * events or config are provided here.
71	 */
72	export interface GuardContext {
73	  /** For session_fail: failure classifier result. */
74	  classifierResult?: FailureClass;
75	  /** For session_ok / post_command_action=continue: are there more phases? */
76	  morePhases?: boolean;
77	  /** For session_ok: all post commands resolved to continue. */
78	  allPostCommandsOk?: boolean;
79	  /** For session_ok: artifact validators passed. */
80	  validatorsOk?: boolean;
81	  /** For session_ok: items_from diff check passed. */
82	  diffCheckOk?: boolean;
83	  /** For post_command_action: the resolved action from the post command. */
84	  postCommandAction?: ResolvedAction;
85	  /** For pre_command_failed: which action kind fired. */
86	  preCommandAction?: 'fail' | 'stop-and-ask';
87	  /**
88	   * Per-phase retry configuration.  Defaults to DEFAULT_MAX_OUTER_RETRIES /
89	   * DEFAULT_RETRY_LADDER when not supplied.
90	   */
91	  maxOuterRetries?: number;
92	  retryLadder?: readonly RetryMode[];
93	  /**
94	   * For awaiting_retry → backoff_elapsed: the retry mode chosen when we
95	   * entered awaiting_retry.  The caller must pass this back so the engine
96	   * can return it (used by the orchestration loop to assemble the prompt).
97	   * If absent, the engine derives it from ladder[retry_count - 1].
98	   */
99	  currentRetryMode?: Exclude<RetryMode, 'awaiting_user'>;
100	  /** For phase advance: the name of the next phase in the stage. */
101	  nextPhase?: string;
102	}
103	
104	// ---------------------------------------------------------------------------
105	// Public types — input / output
106	// ---------------------------------------------------------------------------
107	
108	export interface ApplyItemTransitionParams {
109	  db: DbPool;
110	  workflowId: string;
111	  itemId: string;
112	  sessionId: string | null;
113	  /** Stage ID the item is executing within. */
114	  stage: string;
115	  /** Current phase name (free-text label). */
116	  phase: string;
117	  /** Attempt number for correlation in the events table. */
118	  attempt: number;
119	  event: Event;
120	  guardCtx?: GuardContext;
121	}
122	
123	export interface ApplyItemTransitionResult {
124	  /** New state after the transition (same as old if no-op). */
125	  newState: State;
126	  /** New current_phase after the transition. */
127	  newPhase: string | null;
128	  /** Declarative side-effect labels for the caller to execute. */
129	  sideEffects: readonly string[];
130	  /**
131	   * Retry mode to use for the next session when newState = 'awaiting_retry'.
132	   * Absent for all other newState values.
133	   */
134	  retryMode?: Exclude<RetryMode, 'awaiting_user'>;
135	  /** True if dependents were cascade-blocked within the same transaction. */
136	  cascadeBlocked: boolean;
137	  /** True if all items in the stage reached terminal states this transition. */
138	  stageComplete: boolean;
139	}
140	
141	// ---------------------------------------------------------------------------
142	// Internal row types
143	// ---------------------------------------------------------------------------
144	
145	interface ItemRow {
146	  id: string;
147	  workflow_id: string;
148	  stage_id: string;
149	  status: string;
150	  current_phase: string | null;
151	  depends_on: string | null;
152	  retry_count: number;
153	  blocked_reason: string | null;
154	  updated_at: string;
155	}
156	
157	interface WorkflowRow {
158	  id: string;
159	  status: string;
160	  current_stage: string | null;
161	  worktree_path: string | null;
162	  pipeline: string;
163	}
164	
165	interface SessionRunRow {
166	  id: string;
167	  item_id: string | null;
168	  phase: string;
169	  pid: number | null;
170	  pgid: number | null;
171	  status: string;
172	}
173	
174	// ---------------------------------------------------------------------------
175	// Internal: SQLite helpers (all take a raw Database connection — within txn)
176	// ---------------------------------------------------------------------------
177	
178	interface WriteEventParams {
179	  ts: string;
180	  workflowId: string;
181	  itemId: string | null;
182	  sessionId: string | null;
183	  stage: string | null;
184	  phase: string | null;
185	  attempt: number | null;
186	  eventType: string;
187	  level: 'debug' | 'info' | 'warn' | 'error';
188	  message: string;
189	  extra?: string | null;
190	}
191	
192	// eslint-disable-next-line @typescript-eslint/no-explicit-any
193	type SqliteDb = { prepare(sql: string): any };
194	
195	function writeEvent(db: SqliteDb, p: WriteEventParams): void {
196	  db.prepare(`
197	    INSERT INTO events
198	      (ts, workflow_id, item_id, session_id, stage, phase, attempt,
199	       event_type, level, message, extra)
200	    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
201	  `).run(
202	    p.ts,
203	    p.workflowId,
204	    p.itemId,
205	    p.sessionId,
206	    p.stage,
207	    p.phase,
208	    p.attempt,
209	    p.eventType,
210	    p.level,
211	    p.message,
212	    p.extra ?? null,
213	  );
214	}
215	
216	function writePendingAttention(
217	  db: SqliteDb,
218	  workflowId: string,
219	  kind: string,
220	  payload: Record<string, unknown>,
221	  now: string,
222	): void {
223	  db.prepare(`
224	    INSERT INTO pending_attention (workflow_id, kind, payload, created_at)
225	    VALUES (?, ?, ?, ?)
226	  `).run(workflowId, kind, JSON.stringify(payload), now);
227	}
228	
229	// ---------------------------------------------------------------------------
230	// Internal: derive pending_attention kind from side-effect labels
231	// ---------------------------------------------------------------------------
232	
233	const PENDING_ATTENTION_LABELS: Record<string, string> = {
234	  'insert pending_attention{kind=bootstrap_failed}': 'bootstrap_failed',
235	  'insert pending_attention': 'awaiting_user_retry',
236	  'insert pending_attention{kind=revisit_limit}': 'revisit_limit',
237	  'insert pending_attention{kind=stage_needs_approval}': 'stage_needs_approval',
238	};
239	
240	function pendingAttentionKindFromEffects(
241	  sideEffects: readonly string[],
242	): string | null {
243	  for (const effect of sideEffects) {
244	    const kind = PENDING_ATTENTION_LABELS[effect];
245	    if (kind) return kind;
246	    // Fuzzy match for labels containing 'pending_attention'
247	    if (effect.includes('pending_attention') && effect.includes('insert')) {
248	      const m = /kind=([^}]+)/.exec(effect);
249	      return m ? m[1] : 'awaiting_user_retry';
250	    }
251	  }
252	  return null;
253	}
254	
255	// ---------------------------------------------------------------------------
256	// Internal: revisit counter (RC-3: per item_id + destination_phase pair)
257	// ---------------------------------------------------------------------------
258	
259	function countRevisitEvents(
260	  db: SqliteDb,
261	  itemId: string,
262	  destination: string,
263	): number {
264	  const row = db
265	    .prepare(`
266	      SELECT COUNT(*) AS cnt FROM events
267	       WHERE item_id = ?
268	         AND event_type = 'prepost.revisit'
269	         AND json_extract(extra, '$.destination') = ?
270	    `)
271	    .get(itemId, destination) as { cnt: number };
272	  return row.cnt;
273	}
274	
275	function insertRevisitEvent(
276	  db: SqliteDb,
277	  p: { workflowId: string; itemId: string; sessionId: string | null; stage: string; phase: string; attempt: number },
278	  destination: string,
279	  now: string,
280	): void {
281	  writeEvent(db, {
282	    ts: now,
283	    workflowId: p.workflowId,
284	    itemId: p.itemId,
285	    sessionId: p.sessionId,
286	    stage: p.stage,
287	    phase: p.phase,
288	    attempt: p.attempt,
289	    eventType: 'prepost.revisit',
290	    level: 'info',
291	    message: `goto to phase "${destination}"`,
292	    extra: JSON.stringify({ destination }),
293	  });
294	}
295	
296	// ---------------------------------------------------------------------------
297	// Internal: check all depends_on are complete
298	// ---------------------------------------------------------------------------
299	
300	function checkAllDepsComplete(db: SqliteDb, item: ItemRow): boolean {
301	  if (!item.depends_on) return true;
302	  let deps: string[];
303	  try {
304	    deps = JSON.parse(item.depends_on) as string[];
305	  } catch {
306	    return false;
307	  }
308	  if (deps.length === 0) return true;
309	  const placeholders = deps.map(() => '?').join(',');
310	  const rows = db
311	    .prepare(`SELECT status FROM items WHERE id IN (${placeholders})`)
312	    .all(...deps) as { status: string }[];
313	  return rows.length === deps.length && rows.every(r => r.status === 'complete');
314	}
315	
316	// ---------------------------------------------------------------------------
317	// Internal: compute retry decision from item + ctx
318	// ---------------------------------------------------------------------------
319	
320	type RetryOutcome =
321	  | { kind: 'retry'; mode: Exclude<RetryMode, 'awaiting_user'>; nextRetryCount: number }
322	  | { kind: 'exhausted' };
323	
324	function computeRetry(item: ItemRow, ctx: GuardContext): RetryOutcome {
325	  return computeRetryDecision({
326	    retryCount: item.retry_count,
327	    maxOuterRetries: ctx.maxOuterRetries ?? DEFAULT_MAX_OUTER_RETRIES,
328	    retryLadder: ctx.retryLadder ?? DEFAULT_RETRY_LADDER,
329	  });
330	}
331	
332	// ---------------------------------------------------------------------------
333	// Internal: select the concrete outcome for a conditional transition
334	// ---------------------------------------------------------------------------
335	
336	/** States that trigger cascade-blocking of dependents (AC-2). */
337	const CASCADE_TRIGGER_STATES = new Set<State>(['awaiting_user', 'blocked', 'abandoned']);
338	
339	/** States where an item is terminal for stage-completion purposes (AC-1). */
340	const STAGE_TERMINAL_STATES = new Set<string>(['complete', 'blocked', 'abandoned']);
341	
342	interface OutcomeSelection {
343	  to: State;
344	  sideEffects: readonly string[];
345	  newRetryCount?: number;
346	  retryMode?: Exclude<RetryMode, 'awaiting_user'>;
347	  newPhase?: string;
348	}
