0	/**
1	 * Integration tests for the Pipeline Engine (src/server/pipeline/engine.ts).
2	 *
3	 * Uses real SQLite with migrations applied.  No mocks of the database layer.
4	 *
5	 * Coverage:
6	 *   AC-1  Stage advancement fires stage_complete only when ALL items terminal.
7	 *   AC-2  Dependency cascade-blocks transitive dependents in same transaction.
8	 *   AC-3  Retry ladder: attempt 1=continue, 2=fresh_with_failure_summary, 3=exhausted.
9	 *   AC-4  Crash recovery: sets recovery_state, no auto-transition.
10	 *   AC-5  (structural) Pipeline Engine is the only SQLite mutator.
11	 *   AC-6  Every transition committed in db.transaction before side effects.
12	 *   RC-1  No long-lived in-memory state; every call re-reads SQLite.
13	 *   RC-2  Crash recovery sets recovery_state only, no item transitions.
14	 *   RC-3  max_revisits tracked per (item_id, destination_phase) pair.
15	 *   RC-4  needs_approval:true inserts pending_attention{kind=stage_needs_approval}.
16	 *   RC-5  Events table row written for every transition with full correlation.
17	 */
18	
19	import { describe, it, expect, beforeEach, afterEach } from 'vitest';
20	import fs from 'node:fs';
21	import path from 'node:path';
22	import os from 'node:os';
23	import { fileURLToPath } from 'node:url';
24	import { openDbPool } from '../../src/server/storage/db.js';
25	import { applyMigrations } from '../../src/server/storage/migrate.js';
26	import type { DbPool } from '../../src/server/storage/db.js';
27	import {
28	  applyItemTransition,
29	  checkStageComplete,
30	  buildCrashRecovery,
31	} from '../../src/server/pipeline/engine.js';
32	
33	// ---------------------------------------------------------------------------
34	// Test infrastructure
35	// ---------------------------------------------------------------------------
36	
37	const __dirname = path.dirname(fileURLToPath(import.meta.url));
38	const MIGRATIONS_DIR = path.resolve(__dirname, '../..', 'src/server/storage/migrations');
39	
40	let tmpDir: string;
41	let pool: DbPool;
42	
43	beforeEach(() => {
44	  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'yoke-engine-test-'));
45	  const dbPath = path.join(tmpDir, 'test.db');
46	  pool = openDbPool(dbPath);
