59	let wfSeq = 0;
60	let itemSeq = 0;
61	
62	function makeWfId() {
63	  return `wf-${++wfSeq}`;
64	}
65	function makeItemId() {
66	  return `item-${++itemSeq}`;
67	}
68	
69	function insertWorkflow(id: string, opts: { worktreePath?: string; pipeline?: string } = {}) {
70	  pool.writer
71	    .prepare(`
72	      INSERT INTO workflows
73	        (id, name, spec, pipeline, config, status, created_at, updated_at, worktree_path)
74	      VALUES (?, 'test', '{}', ?, '{}', 'in_progress',
75	              '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z', ?)
76	    `)
77	    .run(id, opts.pipeline ?? '[]', opts.worktreePath ?? null);
78	}
79	
80	function insertItem(
81	  id: string,
82	  wfId: string,
83	  stageId: string,
84	  opts: {
85	    status?: string;
86	    phase?: string;
87	    dependsOn?: string[];
88	    retryCount?: number;
89	  } = {},
90	) {
91	  pool.writer
92	    .prepare(`
93	      INSERT INTO items
94	        (id, workflow_id, stage_id, data, status, current_phase,
95	         depends_on, retry_count, updated_at)
96	      VALUES (?, ?, ?, '{}', ?, ?, ?, ?, '2026-01-01T00:00:00Z')
97	    `)
98	    .run(
99	      id,
100	      wfId,
101	      stageId,
102	      opts.status ?? 'pending',
103	      opts.phase ?? 'implement',
104	      opts.dependsOn ? JSON.stringify(opts.dependsOn) : null,
105	      opts.retryCount ?? 0,
106	    );
107	}
108	
109	function insertSession(
110	  id: string,
111	  wfId: string,
112	  opts: { itemId?: string; status?: string; pid?: number | null; phase?: string } = {},
113	) {
114	  pool.writer
115	    .prepare(`
116	      INSERT INTO sessions
117	        (id, workflow_id, item_id, stage, phase, agent_profile,
118	         pid, started_at, status)
119	      VALUES (?, ?, ?, 'stage1', ?, 'claude', ?, '2026-01-01T00:00:00Z', ?)
120	    `)
121	    .run(
122	      id,
123	      wfId,
124	      opts.itemId ?? null,
125	      opts.phase ?? 'implement',
126	      opts.pid !== undefined ? opts.pid : null,
127	      opts.status ?? 'running',
128	    );
129	}
130	
131	function getItem(id: string) {
132	  return pool.writer
133	    .prepare('SELECT * FROM items WHERE id = ?')
134	    .get(id) as {
135	      id: string;
136	      status: string;
137	      current_phase: string | null;
138	      retry_count: number;
139	      blocked_reason: string | null;
140	    } | undefined;
141	}
142	
143	function countEvents(workflowId: string, eventType?: string): number {
144	  const q = eventType
145	    ? pool.writer
146	        .prepare('SELECT COUNT(*) AS n FROM events WHERE workflow_id = ? AND event_type = ?')
147	        .get(workflowId, eventType)
148	    : pool.writer
149	        .prepare('SELECT COUNT(*) AS n FROM events WHERE workflow_id = ?')
150	        .get(workflowId);
151	  return (q as { n: number }).n;
152	}
153	
154	function countPendingAttention(workflowId: string): number {
155	  const row = pool.writer
156	    .prepare('SELECT COUNT(*) AS n FROM pending_attention WHERE workflow_id = ?')
157	    .get(workflowId) as { n: number };
158	  return row.n;
159	}
160	
161	function pendingAttentionKinds(workflowId: string): string[] {
162	  const rows = pool.writer
163	    .prepare('SELECT kind FROM pending_attention WHERE workflow_id = ?')
164	    .all(workflowId) as { kind: string }[];
165	  return rows.map(r => r.kind);
166	}
