351	/**
352	 * Evaluate guards for a conditional TransitionResult and return the
353	 * concrete outcome.
354	 *
355	 * This function is the authoritative guard implementation for every
356	 * conditional (State × Event) pair.  The TRANSITIONS table provides the
357	 * documented outcomes; this function implements the guards that select one.
358	 *
359	 * Called only from within a db.transaction() callback, so the db parameter
360	 * is the raw writer connection (safe to read from).
361	 */
362	function selectConditionalOutcome(
363	  result: { outcomes: readonly { to: State; guard: string; sideEffects: readonly string[] }[] },
364	  currentState: State,
365	  event: Event,
366	  item: ItemRow,
367	  workflow: WorkflowRow,
368	  db: SqliteDb,
369	  ctx: GuardContext,
370	  now: string,
371	  correlationParams: {
372	    workflowId: string;
373	    itemId: string;
374	    sessionId: string | null;
375	    stage: string;
376	    phase: string;
377	    attempt: number;
378	  },
379	): OutcomeSelection {
380	  const o = result.outcomes;
381	
382	  switch (`${currentState}:${event}`) {
383	    // -----------------------------------------------------------------------
384	    // pending → deps_satisfied
385	    // Guard: all depends_on items have status = 'complete'
386	    // -----------------------------------------------------------------------
387	    case 'pending:deps_satisfied': {
388	      if (checkAllDepsComplete(db, item)) {
389	        // o[0]: all deps complete → ready
390	        return { to: o[0].to, sideEffects: o[0].sideEffects };
391	      }
392	      // Guard failed: deps not yet complete → no-op (return current state)
393	      return { to: currentState, sideEffects: [] };
394	    }
395	
396	    // -----------------------------------------------------------------------
397	    // ready → phase_start
398	    // Guard: worktree_path null → bootstrapping; else → in_progress
399	    // -----------------------------------------------------------------------
400	    case 'ready:phase_start': {
401	      const idx = workflow.worktree_path == null ? 0 : 1;
402	      return { to: o[idx].to, sideEffects: o[idx].sideEffects };
403	    }
404	
405	    // -----------------------------------------------------------------------
406	    // in_progress → pre_command_failed
407	    // Guard: action kind + retry budget
408	    // -----------------------------------------------------------------------
409	    case 'in_progress:pre_command_failed': {
410	      const action = ctx.preCommandAction ?? 'fail';
411	      if (action === 'stop-and-ask') {
412	        // o[2]: stop-and-ask → awaiting_user
413	        return { to: o[2].to, sideEffects: o[2].sideEffects };
414	      }
415	      // action = 'fail' — check retry budget
416	      const decision = computeRetry(item, ctx);
417	      if (decision.kind === 'retry') {
418	        // o[0]: fail + budget > 0 → awaiting_retry
419	        return {
420	          to: o[0].to,
421	          sideEffects: o[0].sideEffects,
422	          newRetryCount: decision.nextRetryCount,
423	          retryMode: decision.mode,
424	        };
425	      }
426	      // o[1]: fail + exhausted → awaiting_user
427	      return { to: o[1].to, sideEffects: o[1].sideEffects };
428	    }
429	
430	    // -----------------------------------------------------------------------
431	    // in_progress → session_ok
432	    // Guard: validatorsOk ∧ diffCheckOk ∧ allPostCommandsOk ∧ morePhases?
433	    // -----------------------------------------------------------------------
434	    case 'in_progress:session_ok': {
435	      const morePhases = ctx.morePhases ?? false;
436	      const idx = morePhases ? 0 : 1;
437	      // o[0]: more phases → in_progress (advance current_phase)
438	      // o[1]: last phase  → complete
439	      const newPhase = morePhases ? (ctx.nextPhase ?? item.current_phase ?? undefined) : undefined;
440	      return { to: o[idx].to, sideEffects: o[idx].sideEffects, newPhase };
441	    }
442	
443	    // -----------------------------------------------------------------------
444	    // in_progress → post_command_action
445	    // Guard: action kind, morePhases, revisit count
446	    //   o[0]: continue + more phases  → in_progress
447	    //   o[1]: continue + last phase   → complete
448	    //   o[2]: goto + within limit     → in_progress
449	    //   o[3]: goto + limit exceeded   → awaiting_user
450	    //   o[4]: retry                   → awaiting_retry
451	    //   o[5]: stop-and-ask            → awaiting_user
452	    //   o[6]: stop                    → abandoned
453	    //   o[7]: fail + budget > 0       → awaiting_retry
454	    //   o[8]: fail + exhausted        → awaiting_user
455	    // -----------------------------------------------------------------------
456	    case 'in_progress:post_command_action': {
457	      const action = ctx.postCommandAction;
458	      if (!action) {
459	        throw new Error(
460	          'post_command_action event requires guardCtx.postCommandAction',
461	        );
462	      }
463	      const morePhases = ctx.morePhases ?? false;
464	
465	      if (action.kind === 'continue') {
466	        const idx = morePhases ? 0 : 1;
467	        const newPhase =
468	          morePhases ? (ctx.nextPhase ?? item.current_phase ?? undefined) : undefined;
469	        return { to: o[idx].to, sideEffects: o[idx].sideEffects, newPhase };
470	      }
471	
472	      if (action.kind === 'goto' && action.goto) {
473	        const destination = action.goto;
474	        const maxRevisits = action.maxRevisits ?? 3;
475	        const existingCount = countRevisitEvents(db, correlationParams.itemId, destination);
476	        if (existingCount + 1 > maxRevisits) {
477	          // o[3]: limit exceeded → awaiting_user (RC-3)
478	          return { to: o[3].to, sideEffects: o[3].sideEffects };
479	        }
480	        // Insert revisit tracking event inside same transaction
481	        insertRevisitEvent(db, correlationParams, destination, now);
482	        // o[2]: within limit → in_progress
483	        return { to: o[2].to, sideEffects: o[2].sideEffects, newPhase: destination };
484	      }
485	
486	      if (action.kind === 'retry') {
487	        const decision = computeRetry(item, ctx);
488	        if (decision.kind === 'retry') {
489	          // o[4]: retry + budget → awaiting_retry
490	          return {
491	            to: o[4].to,
492	            sideEffects: o[4].sideEffects,
493	            newRetryCount: decision.nextRetryCount,
494	            retryMode: decision.mode,
495	          };
496	        }
497	        // Exhausted: use awaiting_user (o[5] is stop-and-ask, so fall through)
498	        return { to: 'awaiting_user', sideEffects: [] };
499	      }
500	
501	      if (action.kind === 'stop-and-ask') {
502	        // o[5]: stop-and-ask → awaiting_user
503	        return { to: o[5].to, sideEffects: o[5].sideEffects };
504	      }
505	
506	      if (action.kind === 'stop') {
507	        // o[6]: stop → abandoned
508	        return { to: o[6].to, sideEffects: o[6].sideEffects };
509	      }
510	
511	      if (action.kind === 'fail') {
512	        const decision = computeRetry(item, ctx);
513	        if (decision.kind === 'retry') {
514	          // o[7]: fail + budget → awaiting_retry
515	          return {
516	            to: o[7].to,
517	            sideEffects: o[7].sideEffects,
518	            newRetryCount: decision.nextRetryCount,
519	            retryMode: decision.mode,
520	          };
521	        }
522	        // o[8]: fail + exhausted → awaiting_user
523	        return { to: o[8].to, sideEffects: o[8].sideEffects };
524	      }
525	
526	      throw new Error(`Unhandled post_command_action kind: ${action.kind}`);
527	    }
528	
529	    // -----------------------------------------------------------------------
530	    // in_progress → validator_fail
531	    // Guard: retry budget > 0
532	    // -----------------------------------------------------------------------
533	    case 'in_progress:validator_fail': {
534	      const decision = computeRetry(item, ctx);
535	      if (decision.kind === 'retry') {
536	        // o[0]: budget > 0 → awaiting_retry
537	        return {
538	          to: o[0].to,
539	          sideEffects: o[0].sideEffects,
540	          newRetryCount: decision.nextRetryCount,
541	          retryMode: decision.mode,
542	        };
543	      }
544	      return { to: 'awaiting_user', sideEffects: [] };
545	    }
546	
547	    // -----------------------------------------------------------------------
548	    // in_progress → diff_check_fail
549	    // Guard: retry budget > 0 (classifier = policy implicit)
550	    // -----------------------------------------------------------------------
551	    case 'in_progress:diff_check_fail': {
552	      const decision = computeRetry(item, ctx);
553	      if (decision.kind === 'retry') {
554	        // o[0]: budget > 0 → awaiting_retry
555	        return {
556	          to: o[0].to,
557	          sideEffects: o[0].sideEffects,
558	          newRetryCount: decision.nextRetryCount,
559	          retryMode: decision.mode,
560	        };
561	      }
562	      return { to: 'awaiting_user', sideEffects: [] };
563	    }
564	
565	    // -----------------------------------------------------------------------
566	    // in_progress → session_fail
567	    // Guard: classifier result + retry budget
568	    //   o[0]: transient + budget > 0 → awaiting_retry
569	    //   o[1]: permanent              → awaiting_user
570	    //   o[2]: unknown                → awaiting_user
571	    // -----------------------------------------------------------------------
572	    case 'in_progress:session_fail': {
573	      const classifier = ctx.classifierResult ?? 'unknown';
574	      if (classifier === 'transient') {
575	        const decision = computeRetry(item, ctx);
576	        if (decision.kind === 'retry') {
577	          return {
578	            to: o[0].to,
579	            sideEffects: o[0].sideEffects,
580	            newRetryCount: decision.nextRetryCount,
581	            retryMode: decision.mode,
582	          };
583	        }
584	        // Budget exhausted even though transient — treat as retries_exhausted
585	        return { to: 'awaiting_user', sideEffects: [] };
586	      }
587	      if (classifier === 'permanent') {
588	        return { to: o[1].to, sideEffects: o[1].sideEffects };
589	      }
590	      // unknown / policy → awaiting_user (safe default, D07)
591	      return { to: o[2].to, sideEffects: o[2].sideEffects };
592	    }
593	
594	    // -----------------------------------------------------------------------
595	    // awaiting_retry → backoff_elapsed
596	    // Guard: retry budget remaining
597	    // -----------------------------------------------------------------------
598	    case 'awaiting_retry:backoff_elapsed': {
599	      const maxOuter = ctx.maxOuterRetries ?? DEFAULT_MAX_OUTER_RETRIES;
600	      const ladder = ctx.retryLadder ?? DEFAULT_RETRY_LADDER;
601	      // retry_count was already incremented when we entered awaiting_retry.
602	      // The mode for the upcoming session is the one that was chosen then.
603	      // If the caller stored it in guardCtx.currentRetryMode, use that;
604	      // otherwise re-derive from ladder[retry_count - 1].
605	      if (item.retry_count <= 0 || item.retry_count > maxOuter) {
606	        return { to: 'awaiting_user', sideEffects: [] };
607	      }
608	      const retryMode: RetryMode =
609	        ctx.currentRetryMode ??
610	        (ladder[item.retry_count - 1] ?? 'awaiting_user');
611	      if (retryMode === 'awaiting_user') {
612	        return { to: 'awaiting_user', sideEffects: [] };
613	      }
614	      return {
615	        to: o[0].to,
616	        sideEffects: o[0].sideEffects,
617	        retryMode: retryMode as Exclude<RetryMode, 'awaiting_user'>,
618	      };
619	    }
620	
621	    default:
622	      throw new Error(
623	        `Unhandled conditional transition guard for (${currentState}, ${event})`,
624	      );
625	  }
626	}
