918	// ---------------------------------------------------------------------------
919	// checkStageComplete — public
920	// ---------------------------------------------------------------------------
921	
922	/** Terminal states for stage-completion purposes (AC-1). */
923	const TERMINAL_FOR_STAGE = ['complete', 'blocked', 'abandoned'];
924	
925	/**
926	 * Check whether all items in a stage have reached a terminal state.
927	 *
928	 * A stage is complete when every item's status ∈ {complete, blocked,
929	 * abandoned} (AC-1). A single non-terminal item prevents advancement.
930	 *
931	 * Re-reads SQLite on every call (RC-1: no caching).
932	 *
933	 * @returns true if ALL items in the stage are terminal, false otherwise.
934	 *          Returns false if there are no items in the stage.
935	 */
936	export function checkStageComplete(
937	  db: DbPool,
938	  workflowId: string,
939	  stageId: string,
940	): boolean {
941	  return checkStageCompleteInTxn(db.reader(), workflowId, stageId);
942	}
943	
944	/** Same as checkStageComplete but takes a raw connection (for use within txn). */
945	function checkStageCompleteInTxn(
946	  db: SqliteDb,
947	  workflowId: string,
948	  stageId: string,
949	): boolean {
950	  const row = db
951	    .prepare(`
952	      SELECT
953	        COUNT(*) AS total,
954	        SUM(CASE WHEN status IN ('complete','blocked','abandoned') THEN 1 ELSE 0 END) AS terminal
955	      FROM items
956	      WHERE workflow_id = ? AND stage_id = ?
957	    `)
958	    .get(workflowId, stageId) as { total: number; terminal: number | null };
959	
960	  const { total, terminal } = row;
961	  return total > 0 && (terminal ?? 0) >= total;
962	}
