982	/**
983	 * Rebuild the crash-recovery projection from SQLite on startup (AC-4).
984	 *
985	 * For each non-terminal workflow, finds sessions with status='running' and
986	 * a non-null PID.  Probes each PID with kill(pid, 0): ESRCH means the
987	 * process is gone (stale).
988	 *
989	 * For workflows with stale sessions, sets recovery_state JSON on the
990	 * workflows row.  Does NOT apply any item-state transitions (AC-4 /RC-2:
991	 * "no auto-transition; user_retry or auto_resume fires the normal row").
992	 *
993	 * @returns list of workflows affected (recovery_state written).
994	 */
995	export function buildCrashRecovery(db: DbPool): WorkflowRecoveryInfo[] {
996	  const now = new Date().toISOString();
997	
