describe('max_revisits — RC-3', () => {
  it('goto within max_revisits → in_progress with destination phase', () => {
    const wfId = makeWfId();
    const itemId = makeItemId();
    insertWorkflow(wfId);
    insertItem(itemId, wfId, 'stage1', { status: 'in_progress', phase: 'review' });

