                            event_type, level, message, extra)
        VALUES ('2026-01-01T00:00:00Z', ?, ?, null, 'stage1', 'review', ?,
                'prepost.revisit', 'info', 'goto', '{"destination":"implement"}')
      `).run(wfId, item1, i);
    }

    // item2 has 0 revisits — should still work
    const result = applyItemTransition({
      db: pool,
      workflowId: wfId,
      itemId: item2,
      sessionId: null,
      stage: 'stage1',
      phase: 'review',
      attempt: 1,
