      itemId,
      sessionId: null,
      stage: 'stage1',
      phase: 'review',
      attempt: 1,
      event: 'post_command_action',
      guardCtx: {
        postCommandAction: { kind: 'goto', goto: 'implement', maxRevisits: 3 },
      },
    });

    expect(countEvents(wfId, 'prepost.revisit')).toBe(1);
  });
});

