        (id, name, spec, pipeline, config, status, created_at, updated_at, worktree_path)
      VALUES (?, 'test', '{}', ?, '{}', 'in_progress',
              '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z', ?)
    `)
    .run(id, opts.pipeline ?? '[]', opts.worktreePath ?? null);
}

function insertItem(
  id: string,
  wfId: string,
  stageId: string,
  opts: {
    status?: string;
    phase?: string;
    dependsOn?: string[];
    retryCount?: number;
  } = {},
